select approvalid, approvalname, seq, approverid, approvername
  from cotdl.tbl_piiapprovaluser 
 where approvalid= #{approvalid, jdbcType=VARCHAR}
   and approverid= #{approverid, jdbcType=VARCHAR}

mapper.delete:
delete from cotdl.tbl_piiapprovaluser 
where approvalid= #{approvalid, jdbcType=VARCHAR}
  and approverid= #{approverid, jdbcType=VARCHAR}

mapper.update:
		update cotdl.tbl_piiapprovaluser
		set 
			seq= #{seq, jdbcType=VARCHAR},
			approvername= #{approvername, jdbcType=VARCHAR}
		where approvalid= #{approvalid, jdbcType=VARCHAR}
          and approverid= #{approverid, jdbcType=VARCHAR}

mapper.select:
 
		 
		select 
			approvalid, approvalname, seq, approverid, approvername
		from ( 
				select 
					 ROWNUM rn, approvalid, approvalname, seq, approverid, approvername
				from (
						select approvalid, approvalname, seq, approverid, approvername
						  from cotdl.tbl_piiapprovaluser 
						 order by approvalid , approverid
					 ) a
				where
		
	    
		 
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by approvalid , approverid
			  ) f
		where rn > (#{pagenum} -1) * #{amount} 
		order by approvalid , approverid

select  count(1)
from cotdl.tbl_piiapprovaluser
where approvalid= #{approvalid, jdbcType=VARCHAR}
  and approverid= #{approverid, jdbcType=VARCHAR}
